declare nofpclass(nan zero sub norm) float @returns_inf()

define nofpclass(snan) float @inf__maximumnum__not_nan(float nofpclass(nan) %not.nan) {
  %inf.or.nan = call float @returns_inf()
  %result = call float @llvm.maximumnum.f32(float %inf.or.nan, float %not.nan)
  ret float %result
}

define nofpclass(nsub) float @lhs_must_be_ninf(float %unknown, float nofpclass(nan pinf zero sub norm) %must.be.ninf) {
  %result = call float @llvm.maximumnum.f32(float %must.be.ninf, float %unknown)
  ret float %result
}

define nofpclass(nsub) float @lhs_must_be_ninf_rhs_non_nan(float nofpclass(nan) %not.nan, float nofpclass(nan pinf zero sub norm) %must.be.ninf) {
  %result = call float @llvm.maximumnum.f32(float %must.be.ninf, float %not.nan)
  ret float %result
}

define nofpclass(nsub) float @lhs_must_be_pinf(float %unknown, float nofpclass(nan ninf zero sub norm) %must.be.pinf) {
  %result = call float @llvm.maximumnum.f32(float %must.be.pinf, float %unknown)
  ret float %result
}

define nofpclass(nsub) float @lhs_must_be_pinf_rhs_non_nan(float nofpclass(nan) %not.nan, float nofpclass(nan ninf zero sub norm) %must.be.pinf) {
  %result = call float @llvm.maximumnum.f32(float %must.be.pinf, float %not.nan)
  ret float %result
}

